      await loadAuth(true);
    } catch (error) {
      setAuthError(error instanceof Error ? error.message : 'No se pudo cancelar login de Codex');
    } finally {
      setAuthActionBusy(false);
    }
  };

  const logoutDeviceAuth = async () => {
