function clampPercentage(value) {
  if (!Number.isFinite(value)) return null;
  return Math.max(0, Math.min(100, Number(value)));
}

function normalizeRateWindow(rawWindow) {
  if (!rawWindow || typeof rawWindow !== 'object') {
